'use client'

import Link from 'next/link'
import { Button } from '@/components/ui/button'
import { Empty } from '@/components/ui/empty'
import { useIssues } from '@/hooks/use-issues'
import { Skeleton } from '@/components/ui/skeleton'

interface TrendingSectionProps {
  limit?: number
}

export default function TrendingSection({ limit = 3 }: TrendingSectionProps) {
  const { issues, isLoading, error } = useIssues()
  
  // Sort by confirmations to get trending issues
  const trendingIssues = issues
    .sort((a, b) => b.confirmations - a.confirmations)
    .slice(0, limit)

  return (
    <section className="space-y-4">
      <div>
        <h2 className="text-2xl font-bold text-foreground mb-2">Trending Problems</h2>
        <p className="text-sm text-muted-foreground">Most reported issues in your area</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 mb-4">
        {isLoading ? (
          Array.from({ length: 3 }).map((_, i) => (
            <Skeleton key={i} className="h-40 bg-secondary" />
          ))
        ) : error ? (
          <Empty 
            icon="alert-circle"
            title="Error loading trending"
            description="Failed to load trending issues. Please try again."
          />
        ) : trendingIssues.length === 0 ? (
          <Empty 
            icon="trending-up"
            title="No trending issues"
            description="Check back soon for trending problems in your area"
          />
        ) : null}
      </div>

      <Link href="/citizen/trending">
        <Button variant="outline" className="w-full border-border hover:bg-secondary">
          View All Trending Problems
        </Button>
      </Link>
    </section>
  )
}
