'use client'

import { useState } from 'react'
import { Mic, Camera } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Card } from '@/components/ui/card'
import { Textarea } from '@/components/ui/textarea'
import { Input } from '@/components/ui/input'
import { Complaint } from '@/lib/types'

interface ComplaintFormProps {
  onSubmit?: (data: Omit<Complaint, 'id' | 'createdAt' | 'updatedAt'>) => Promise<void>
  isLoading?: boolean
  categories?: string[]
}

export default function ComplaintForm({ 
  onSubmit, 
  isLoading = false,
  categories = ['Pothole', 'Street Light', 'Water Leakage', 'Garbage', 'Traffic', 'Other']
}: ComplaintFormProps) {
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    location: '',
    category: categories[0],
  })
  const [error, setError] = useState<string | null>(null)
  const [imageUrl, setImageUrl] = useState<string | null>(null)

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target
    setFormData(prev => ({ ...prev, [name]: value }))
  }

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    setError(null)

    if (!formData.title.trim() || !formData.description.trim() || !formData.location.trim()) {
      setError('Please fill in all required fields')
      return
    }

    try {
      await onSubmit?.({
        title: formData.title,
        description: formData.description,
        location: formData.location,
        category: formData.category,
        imageUrl: imageUrl || undefined,
        userId: '', // Will be set by the API
        status: 'pending',
      })
      
      // Reset form
      setFormData({
        title: '',
        description: '',
        location: '',
        category: categories[0],
      })
      setImageUrl(null)
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to submit complaint')
    }
  }

  return (
    <Card className="bg-card border-border p-6">
      <form onSubmit={handleSubmit} className="space-y-4">
        {error && (
          <div className="p-3 bg-destructive/10 border border-destructive/50 rounded text-sm text-destructive">
            {error}
          </div>
        )}

        <div className="space-y-2">
          <label className="block text-sm font-medium text-foreground">
            Title *
          </label>
          <Input
            name="title"
            value={formData.title}
            onChange={handleChange}
            placeholder="Brief summary of the problem"
            className="bg-secondary border-border text-foreground placeholder:text-muted-foreground"
            maxLength={100}
          />
        </div>

        <div className="space-y-2">
          <label className="block text-sm font-medium text-foreground">
            Category
          </label>
          <select
            name="category"
            value={formData.category}
            onChange={handleChange}
            className="w-full px-3 py-2 bg-secondary border border-border text-foreground rounded-md focus:outline-none focus:ring-2 focus:ring-accent"
          >
            {categories.map(cat => (
              <option key={cat} value={cat}>{cat}</option>
            ))}
          </select>
        </div>

        <div className="space-y-2">
          <label className="block text-sm font-medium text-foreground">
            Description *
          </label>
          <Textarea
            name="description"
            value={formData.description}
            onChange={handleChange}
            placeholder="Provide details about the problem..."
            className="min-h-24 bg-secondary border-border text-foreground placeholder:text-muted-foreground resize-none"
            maxLength={1000}
          />
        </div>

        <div className="space-y-2">
          <label className="block text-sm font-medium text-foreground">
            Location *
          </label>
          <Input
            name="location"
            value={formData.location}
            onChange={handleChange}
            placeholder="Enter location or address"
            className="bg-secondary border-border text-foreground placeholder:text-muted-foreground"
          />
        </div>

        <div className="flex gap-2 pt-2">
          <Button
            type="button"
            variant="outline"
            size="sm"
            className="border-border hover:bg-secondary gap-2"
            disabled={isLoading}
          >
            <Camera className="w-4 h-4" />
            Camera
          </Button>
          <Button
            type="button"
            variant="outline"
            size="sm"
            className="border-border hover:bg-secondary gap-2"
            disabled={isLoading}
          >
            <Mic className="w-4 h-4" />
            Audio
          </Button>
        </div>

        <Button
          type="submit"
          disabled={isLoading}
          className="w-full bg-accent hover:bg-accent/90 text-accent-foreground font-medium"
        >
          {isLoading ? 'Submitting...' : 'Submit Complaint'}
        </Button>
      </form>
    </Card>
  )
}
