import useSWR from 'swr'
import { Complaint } from '@/lib/types'

const fetcher = (url: string) => fetch(url).then(res => res.json())

export function useComplaints(userId?: string) {
  const query = userId ? `?userId=${encodeURIComponent(userId)}` : ''
  const { data, error, isLoading, mutate } = useSWR<Complaint[]>(
    `/api/complaints${query}`,
    fetcher
  )

  return {
    complaints: data || [],
    isLoading,
    error,
    mutate,
  }
}

export function useComplaint(complaintId: string) {
  const { data, error, isLoading, mutate } = useSWR<Complaint>(
    complaintId ? `/api/complaints/${complaintId}` : null,
    fetcher
  )

  return {
    complaint: data,
    isLoading,
    error,
    mutate,
  }
}

export async function submitComplaint(data: Omit<Complaint, 'id' | 'createdAt' | 'updatedAt'>) {
  const response = await fetch('/api/complaints', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(data),
  })

  if (!response.ok) {
    throw new Error('Failed to submit complaint')
  }

  return response.json()
}
